 1	import {
 2	  type Dispatch,
 3	  type FC,
 4	  type MouseEvent as ReactMouseEvent,
 5	  type SetStateAction,
 6	  useState,
 7	} from 'react';
 8	
 9	import { FormGroup, Select as PfSelect, SelectOption } from '@patternfly/react-core';
10	import { useForkliftTranslation } from '@utils/i18n';
11	import selectToggle from '@utils/selectToggle';
12	
13	import { AFFINITY_TYPE_LABELS } from './utils/constants';
14	import type { AffinityRowData } from './utils/types';
15	
16	type AffinityTypeSelectProps = {
17	  focusedAffinity: AffinityRowData;
18	  setFocusedAffinity: Dispatch<SetStateAction<AffinityRowData>>;
19	};
20	
21	const AffinityTypeSelect: FC<AffinityTypeSelectProps> = ({
22	  focusedAffinity,
23	  setFocusedAffinity,
24	}) => {
25	  const { t } = useForkliftTranslation();
26	
27	  const [isOpen, setIsOpen] = useState(false);
28	
29	  const handleChange = (event: ReactMouseEvent | undefined, value: string | number | undefined) => {
30	    event?.preventDefault();
31	    setFocusedAffinity({ ...focusedAffinity, type: value });
32	    setIsOpen(false);
33	  };
34	
35	  const onToggle = () => {
36	    setIsOpen((prevIsOpen) => !prevIsOpen);
37	  };
38	  return (
39	    <FormGroup fieldId="type" isRequired label={t('Type')}>
40	      <PfSelect
41	        toggle={selectToggle({
42	          isExpanded: isOpen,
43	          onClick: onToggle,
44	          selected: AFFINITY_TYPE_LABELS[focusedAffinity?.type],
45	          testId: 'affinity-type-select',
46	        })}
47	        isOpen={isOpen}
48	        onSelect={handleChange}
49	        selected={focusedAffinity?.type}
50	      >
51	        {Object.entries(AFFINITY_TYPE_LABELS).map(([key, value]) => (
52	          <SelectOption key={key} value={key}>
53	            {value}
54	          </SelectOption>
55	        ))}
56	      </PfSelect>
57	    </FormGroup>
58	  );
59	};
60	
61	export default AffinityTypeSelect;

